import cv2
import numpy as np
import os
from flask import Flask, request, jsonify
from sklearn.svm import SVC
from sklearn.preprocessing import LabelEncoder
import pickle
import face_recognition
import json

app = Flask(__name__)

class FacialRecognitionAPI:
    def __init__(self):
        self.model = SVC(probability=True, kernel='rbf', C=1.0, gamma='scale')
        self.label_encoder = LabelEncoder()
        self.known_faces = []
        self.known_names = []
        self.is_trained = False
        
    def extract_face_features(self, image_path):
        image = cv2.imread(image_path)
        rgb_image = cv2.cvtColor(image, cv2.COLOR_BGR2RGB)
        face_locations = face_recognition.face_locations(rgb_image)
        
        if len(face_locations) == 0:
            return None
            
        face_encodings = face_recognition.face_encodings(rgb_image, face_locations)
        return face_encodings[0] if face_encodings else None
    
    def train_model(self, dataset_path):
        features = []
        labels = []
        
        for person_name in os.listdir(dataset_path):
            person_folder = os.path.join(dataset_path, person_name)
            if not os.path.isdir(person_folder):
                continue
                
            for image_file in os.listdir(person_folder):
                if image_file.lower().endswith(('.png', '.jpg', '.jpeg')):
                    image_path = os.path.join(person_folder, image_file)
                    face_features = self.extract_face_features(image_path)
                    
                    if face_features is not None:
                        features.append(face_features)
                        labels.append(person_name)
        
        if len(features) == 0:
            raise ValueError("No faces found in dataset")
            
        self.model.fit(features, labels)
        self.is_trained = True
        
    def recognize_face(self, image_path):
        if not self.is_trained:
            return {"error": "Model not trained"}
            
        image = cv2.imread(image_path)
        rgb_image = cv2.cvtColor(image, cv2.COLOR_BGR2RGB)
        face_locations = face_recognition.face_locations(rgb_image)
        face_encodings = face_recognition.face_encodings(rgb_image, face_locations)
        
        results = []
        
        for face_encoding in face_encodings:
            # Get probability distribution
            probabilities = self.model.predict_proba([face_encoding])[0]
            class_labels = self.model.classes_
            
            # Create detailed probability distribution
            prob_dict = dict(zip(class_labels, probabilities))
            
            # Get confidence score for the highest probability class
            max_prob = max(probabilities)
            max_class = class_labels[np.argmax(probabilities)]
            
            results.append({
                "face_location": {
                    "top": face_locations[0][0],
                    "right": face_locations[0][1],
                    "bottom": face_locations[0][2],
                    "left": face_locations[0][3]
                },
                "confidence": float(max_prob),
                "predicted_class": max_class,
                "probability_distribution": prob_dict
            })
            
        return results

# Initialize API
face_api = FacialRecognitionAPI()

@app.route('/train', methods=['POST'])
def train_model():
    try:
        dataset_path = request.json.get('dataset_path')
        if not dataset_path:
            return jsonify({"error": "Dataset path required"}), 400
            
        face_api.train_model(dataset_path)
        return jsonify({"status": "Model trained successfully"})
        
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/recognize', methods=['POST'])
def recognize_face():
    try:
        image_path = request.json.get('image_path')
        if not image_path:
            return jsonify({"error": "Image path required"}), 400
            
        results = face_api.recognize_face(image_path)
        return jsonify({"results": results})
        
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/status', methods=['GET'])
def get_status():
    return jsonify({"trained": face_api.is_trained})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)